   530|  const candidateAuthUsers = Array.from(new Map([...matchingEmailUsers, ...matchingPhoneUsers].map((user) => [user.id, user])).values());
   531|  const canonicalAuthUser = candidateAuthUsers
   532|    .slice()
   533|    .sort((left, right) => new Date(left.created_at ?? 0).getTime() - new Date(right.created_at ?? 0).getTime())[0] ?? null;
   534|  const candidateIds = candidateAuthUsers.map((user) => user.id);
